protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // EF Core 9 renamed the discriminator property from "Discriminator" to "$type".
        // Existing 500K documents use "Discriminator", and direct SQL queries reference
        // c.Discriminator — preserve the old name to avoid a full data migration.
        entity.HasDiscriminator<string>("Discriminator");

        // EF Core 9 changed id format from "Product|123" to just "123".
        // Existing documents use the compound format — preserve it so FindAsync
        // and point-reads continue to work against existing data.
        entity.HasRootDiscriminatorInJsonId(true);
    });

    // REMOVED: HasIndex(p => p.Sku)
    // EF Core 9 Cosmos provider now throws at startup for HasIndex calls.
    // Cosmos DB indexing is managed via the container's indexing policy
    // (Azure Portal, Bicep, or Terraform), not through EF Core.
}

